 1	import React, { FC, useState } from 'react';
 2	import { CopyToClipboard as CTC } from 'react-copy-to-clipboard';
 3	import classNames from 'classnames';
 4	
 5	import { Tooltip } from '@patternfly/react-core';
 6	import { CopyIcon, ExternalLinkAltIcon } from '@patternfly/react-icons';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	
 9	type ExternalLinkWithCopyProps = {
10	  additionalClassName?: string;
11	  dataTestID?: string;
12	  link: string;
13	  text?: string;
14	};
15	
16	export const ExternalLinkWithCopy: FC<ExternalLinkWithCopyProps> = ({
17	  additionalClassName,
18	  dataTestID,
19	  link,
20	  text,
21	}) => {
22	  const { t } = useNetworkingTranslation();
23	  const [copied, setCopied] = useState(false);
24	
25	  const tooltipText = copied ? t('Copied to clipboard') : t('Copy to clipboard');
26	  const tooltipContent = [
27	    <span className="co-nowrap" key="nowrap">
28	      {tooltipText}
29	    </span>,
30	  ];
31	
32	  return (
33	    <div className={classNames(additionalClassName)}>
34	      <a data-test-id={dataTestID} href={link} rel="noopener noreferrer" target="_blank">
35	        {text ?? link}
36	        <span className="co-icon-nowrap">
37	          &nbsp;
38	          <span className="co-external-link-with-copy__icon co-external-link-with-copy__externallinkicon">
39	            <ExternalLinkAltIcon />
40	          </span>
41	        </span>
42	      </a>
43	      <span className="co-icon-nowrap">
44	        <Tooltip content={tooltipContent} exitDelay={1250} trigger="click mouseenter focus">
45	          <CTC onCopy={() => setCopied(true)} text={link}>
46	            <span
47	              className="co-external-link-with-copy__icon co-external-link-with-copy__copyicon"
48	              onMouseEnter={() => setCopied(false)}
49	            >
50	              <CopyIcon />
51	              <span className="pf-v6-u-screen-reader">{t('Copy to clipboard')}</span>
52	            </span>
53	          </CTC>
54	        </Tooltip>
55	      </span>
56	    </div>
57	  );
58	};

